import{_ as e,W as a,X as n,Y as s}from"./framework-9a5142fa.js";const i={},t=s(`<ul><li><a href="#1-bash-heredoc">1. Bash Heredoc</a><ul><li><a href="#11-introduction">1.1. Introduction</a></li><li><a href="#12-examples">1.2. Examples</a><ul><li><a href="#121-bash-example">1.2.1. bash example</a></li><li><a href="#122-cat-example">1.2.2. cat example</a></li><li><a href="#123-quotes-example">1.2.3. quotes example</a></li><li><a href="#124-indent-example">1.2.4. indent example</a></li><li><a href="#125-redirect-example">1.2.5. redirect example</a></li><li><a href="#126-pipe-example">1.2.6. pipe example</a></li><li><a href="#127-ssh-example">1.2.7. SSH example</a></li><li><a href="#128-dockerfile">1.2.8. Dockerfile</a></li></ul></li></ul></li></ul><hr><h1 id="_1-bash-heredoc" tabindex="-1"><a class="header-anchor" href="#_1-bash-heredoc" aria-hidden="true">#</a> 1. Bash Heredoc</h1><h2 id="_1-1-introduction" tabindex="-1"><a class="header-anchor" href="#_1-1-introduction" aria-hidden="true">#</a> 1.1. Introduction</h2><p>When writing shell scripts you may be in a situation where you need to pass a multiline block of text or code to an interactive command, such as <code>tee</code>, <code>cat</code>, or <code>sftp</code>.</p><p>In Bash and other shells like Zsh, a Here document (Heredoc) is a type of redirection that allows you to pass multiple lines of input to a command.</p><p>The syntax of writing HereDoc takes the following form:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>COMMAND<span class="token punctuation">]</span> <span class="token operator">&lt;&lt;</span><span class="token punctuation">[</span>-<span class="token punctuation">]</span> <span class="token string">&#39;DELIMITER&#39;</span>
  HERE-DOCUMENT
DELIMITER
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>The first line starts with an optional command followed by the special <strong>redirection operator</strong> <code>&lt;&lt;</code> and the <strong>delimiting identifier</strong>. <ul><li>You can use any string as a delimiting identifier, as long as it is unique enough that it won’t appear within the content. The most commonly used are <code>EOF</code> or <code>END</code>.</li><li>If the delimiting identifier is <strong>unquoted</strong>, the shell will substitute all variables, commands and special characters before passing the here-document lines to the command.</li><li>Appending a minus sign<code>-</code> to the redirection operator <code>&lt;&lt;-</code>, will cause all leading tab characters to be ignored(i.e.<strong>indent</strong>). This allows you to use indentation when writing here-documents in shell scripts. Leading whitespace characters are not allowed, only tab.</li></ul></li><li>The <strong>here-document block</strong> can contain strings, variables, commands and any other type of input.</li><li>The last line ends with the <strong>delimiting identifier</strong>. White space in front of the delimiter is not allowed.</li></ul><h2 id="_1-2-examples" tabindex="-1"><a class="header-anchor" href="#_1-2-examples" aria-hidden="true">#</a> 1.2. Examples</h2><h3 id="_1-2-1-bash-example" tabindex="-1"><a class="header-anchor" href="#_1-2-1-bash-example" aria-hidden="true">#</a> 1.2.1. bash example</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">sudo</span> <span class="token function">apt</span> update <span class="token operator">&amp;&amp;</span> <span class="token punctuation">\\</span>
<span class="token operator">&gt;</span> <span class="token function">sudo</span> <span class="token function">apt</span> upgrade
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">bash</span> <span class="token operator">&lt;&lt;</span> EOF
<span class="token operator">&gt;</span> <span class="token function">sudo</span> <span class="token function">apt</span> update
<span class="token operator">&gt;</span> <span class="token function">sudo</span> <span class="token function">apt</span> upgrade
<span class="token operator">&gt;</span> EOF
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-2-cat-example" tabindex="-1"><a class="header-anchor" href="#_1-2-2-cat-example" aria-hidden="true">#</a> 1.2.2. cat example</h3><p>In this section, we will look at some basic examples of how to use heredoc.</p><p>Heredoc is most often used in combination with the <code>cat</code></p><p>In the following example, we are passing two lines of text containing an environment variable and a command to <code>cat</code> using a here document.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">cat</span> <span class="token operator">&lt;&lt;</span> EOF
<span class="token operator">&gt;</span> The current working directory is: <span class="token environment constant">$PWD</span>
<span class="token operator">&gt;</span> You are logged <span class="token keyword">in</span> as: <span class="token variable"><span class="token variable">$(</span><span class="token function">whoami</span><span class="token variable">)</span></span>
<span class="token operator">&gt;</span> EOF
The current working directory is: /home/linuxize
You are logged <span class="token keyword">in</span> as: linuxize
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>As you can see from the output below, both the variable and the command output are substituted:</p><h3 id="_1-2-3-quotes-example" tabindex="-1"><a class="header-anchor" href="#_1-2-3-quotes-example" aria-hidden="true">#</a> 1.2.3. quotes example</h3><p>Let’s see what will happen if we enclose the delimiter in single or double quotes.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">cat</span> <span class="token operator">&lt;&lt;</span> <span class="token string">&quot;EOF&quot;</span>
<span class="token operator">&gt;</span> The current working directory is: <span class="token environment constant">$PWD</span>
<span class="token operator">&gt;</span> You are logged <span class="token keyword">in</span> as: <span class="token variable"><span class="token variable">$(</span><span class="token function">whoami</span><span class="token variable">)</span></span>
<span class="token operator">&gt;</span> EOF
The current working directory is: <span class="token environment constant">$PWD</span>
You are logged <span class="token keyword">in</span> as: <span class="token variable"><span class="token variable">$(</span><span class="token function">whoami</span><span class="token variable">)</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>You can notice that when the delimiter is quoted no parameter expansion and command substitution is done by the shell.</p><h3 id="_1-2-4-indent-example" tabindex="-1"><a class="header-anchor" href="#_1-2-4-indent-example" aria-hidden="true">#</a> 1.2.4. indent example</h3><p>If you are using a heredoc inside a statement or loop, use the <code>&lt;&lt;-</code> redirection operation that allows you to indent your code.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">cat</span> <span class="token operator">&lt;&lt;-</span> EOF
<span class="token operator">&gt;</span>     Line with a leading tab.
<span class="token operator">&gt;</span> EOF
    Line with a leading tab.
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-5-redirect-example" tabindex="-1"><a class="header-anchor" href="#_1-2-5-redirect-example" aria-hidden="true">#</a> 1.2.5. redirect example</h3><p>Instead of displaying the output on the screen you can redirect it to a file using the <code>&gt;</code>, <code>&gt;&gt;</code> operators.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">cat</span> <span class="token operator">&lt;&lt;</span> EOF <span class="token operator">&gt;</span> file.txt
<span class="token operator">&gt;</span> The current working directory is: <span class="token environment constant">$PWD</span>
<span class="token operator">&gt;</span> You are logged <span class="token keyword">in</span> as: <span class="token variable"><span class="token variable">$(</span><span class="token function">whoami</span><span class="token variable">)</span></span>
<span class="token operator">&gt;</span> EOF
$ <span class="token function">cat</span> file.txt
The current working directory is: /root
You are logged <span class="token keyword">in</span> as: root
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>If the file.txt doesn’t exist it will be created. When using <code>&gt;</code> the file will be overwritten, while the <code>&gt;&gt;</code> will append the output to the file.</p><h3 id="_1-2-6-pipe-example" tabindex="-1"><a class="header-anchor" href="#_1-2-6-pipe-example" aria-hidden="true">#</a> 1.2.6. pipe example</h3><p>The heredoc input can also be piped. In the following example the <code>sed</code> command will replace all instances of the <code>l</code> character with <code>e</code>:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">cat</span> <span class="token operator">&lt;&lt;</span><span class="token string">&#39;EOF&#39;</span> <span class="token operator">|</span>  <span class="token function">sed</span> <span class="token string">&#39;s/l/e/g&#39;</span>
<span class="token operator">&gt;</span> Hello
<span class="token operator">&gt;</span> World
<span class="token operator">&gt;</span> EOF
Heeeo
Wored
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To write the piped data to a file:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">cat</span> <span class="token operator">&lt;&lt;</span><span class="token string">&#39;EOF&#39;</span> <span class="token operator">|</span>  <span class="token function">sed</span> <span class="token string">&#39;s/l/e/g&#39;</span> <span class="token operator">&gt;</span> file.txt
<span class="token operator">&gt;</span> Hello
<span class="token operator">&gt;</span> World
<span class="token operator">&gt;</span> EOF
$ <span class="token function">cat</span> file.txt
Heeeo
Wored
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-7-ssh-example" tabindex="-1"><a class="header-anchor" href="#_1-2-7-ssh-example" aria-hidden="true">#</a> 1.2.7. SSH example</h3><p>Using Heredoc is one of the most convenient and easiest ways to execute multiple commands on a remote system over SSH.</p><p>When using unquoted delimiter make sure you escape all variables, commands and special characters otherwise they will be interpolated locally:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">ssh</span> <span class="token parameter variable">-T</span> user@host.com <span class="token operator">&lt;&lt;</span> EOF
<span class="token operator">&gt;</span> <span class="token builtin class-name">echo</span> <span class="token string">&quot;The current local working directory is: <span class="token environment constant">$PWD</span>&quot;</span>
<span class="token operator">&gt;</span> <span class="token builtin class-name">echo</span> <span class="token string">&quot;The current remote working directory is: \\<span class="token environment constant">$PWD</span>&quot;</span>
<span class="token operator">&gt;</span> EOF
The current <span class="token builtin class-name">local</span> working directory is: /home/linuxize
The current remote working directory is: /home/user
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-8-dockerfile" tabindex="-1"><a class="header-anchor" href="#_1-2-8-dockerfile" aria-hidden="true">#</a> 1.2.8. Dockerfile</h3><p>This feature is merged into Dockfile.</p><div class="language-docker line-numbers-mode" data-ext="docker"><pre class="language-docker"><code><span class="token instruction"><span class="token keyword">RUN</span> &lt;&lt; EOF</span>
apt update
apt upgrade
EOF
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,42),o=[t];function l(r,c){return a(),n("div",null,o)}const p=e(i,[["render",l],["__file","Bash Heredoc.html.vue"]]);export{p as default};
